// Combine transcript segments into clean text
const episode = $('Code in JavaScript').item.json;
let transcript = '';

try {
  const transcriptData = $input.first().json;

  // Handle different transcript response formats
  if (transcriptData.transcripts) {
    // youtube-transcript.io format
    transcript = transcriptData.transcripts
      .map(t => t.text || t.snippet || '')
      .join(' ')
      .replace(/\s+/g, ' ')
      .trim();
  } else if (transcriptData.transcript) {
    // Alternative format
    if (Array.isArray(transcriptData.transcript)) {
      transcript = transcriptData.transcript
        .map(t => t.text || t.snippet || '')
        .join(' ')
        .replace(/\s+/g, ' ')
        .trim();
    } else {
      transcript = transcriptData.transcript;
    }
  } else if (Array.isArray(transcriptData)) {
    transcript = transcriptData
      .map(t => t.text || t.snippet || '')
      .join(' ')
      .replace(/\s+/g, ' ')
      .trim();
  }
} catch(e) {
  // If transcript fetch failed, use the video description as fallback
  transcript = episode.description || 'Transcript not available.';
}

// Truncate if too long (Claude has context limits)
if (transcript.length > 80000) {
  transcript = transcript.substring(0, 80000) + '... [transcript truncated]';
}

return [{ json: { ...episode, transcript } }];

// Parse Claude's response and build the complete blog post JSON
const episode = $('Clean Transcript').item.json;
const claudeResponse = $input.first().json;

let blogData;
try {
  // Extract text content from Claude's response
  const text = claudeResponse.content[0].text;
  // Clean any accidental markdown wrapping
  const clean = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  blogData = JSON.parse(clean);
} catch(e) {
  throw new Error('Failed to parse Claude response: ' + e.message);
}

// Build the complete blog post object
const post = {
  slug: episode.slug,
  title: blogData.title || episode.title,
  episodeNumber: blogData.episodeNumber || 0,
  // TODO: If episodeNumber is 0, fetch posts.json from GitHub and set to max + 1
  // For now, 0 flags it for manual fix
  guestName: blogData.guestName || '',
  guestBio: blogData.guestBio || '',
  publishedAt: episode.publishedAt,
  duration: episode.durationFormatted,
  thumbnail: episode.thumbnail,
  youtubeUrl: episode.youtubeUrl,
  spotifyUrl: 'https://open.spotify.com/show/03FuFRyzkaWhZkk5yxFePJ',
  appleUrl: 'https://podcasts.apple.com/us/podcast/the-manage-her/id1809208475',
  excerpt: blogData.excerpt || '',
  metaDescription: blogData.metaDescription || '',
  topics: blogData.topics || [],
  keyTakeaways: blogData.keyTakeaways || [],
  guestLinks: blogData.guestLinks || [],
  pullQuotes: blogData.pullQuotes || [],
  timestamps: blogData.timestamps || [],
  quiz: blogData.quiz || null,
  transcript: $('Clean Transcript').first().json.transcript || '',
  content: blogData.content || ''
};

// Also build the posts.json index entry
const indexEntry = {
  slug: post.slug,
  title: post.title,
  episodeNumber: post.episodeNumber,
  guestName: post.guestName,
  publishedAt: post.publishedAt,
  duration: post.duration,
  thumbnail: post.thumbnail,
  excerpt: post.excerpt,
  topics: post.topics,
  youtubeUrl: post.youtubeUrl
};

return [{ json: { post, indexEntry, slug: episode.slug } }];

// Update the posts.json index with the new entry
const newEntry = $('Build Blog JSON').item.json.indexEntry;
const response = $input.first().json;

let existingPosts = [];
let sha = '';

try {
  if (response.content) {
    const decoded = Buffer.from(response.content, 'base64').toString('utf-8');
    const parsed = JSON.parse(decoded);
    existingPosts = parsed.posts || [];
    sha = response.sha;
  }
} catch(e) {
  existingPosts = [];
}

// Add new entry at the beginning (most recent first)
// Remove any existing entry with the same slug
existingPosts = existingPosts.filter(p => p.slug !== newEntry.slug);
existingPosts.unshift(newEntry);

const updatedIndex = { posts: existingPosts };
const content = Buffer.from(JSON.stringify(updatedIndex, null, 2)).toString('base64');

const body = {
  message: `Update blog index: add ${newEntry.title}`,
  content,
  branch: 'main'
};

if (sha) body.sha = sha;

return [{ json: body }];

// Process episodes from the webhook response
const episodes = $input.first().json.episodes || [];

function makeSlug(title) {
  return title
    .toLowerCase()
    .replace(/^ep\.?\s*\d+\s*:?\s*/i, '')
    .replace(/\|.*$/g, '')
    .replace(/the manage her:?\s*/gi, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .substring(0, 120);
}

function formatDuration(iso) {
  const match = (iso || '').match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!match) return '30 min';
  const h = parseInt(match[1]||0);
  const m = parseInt(match[2]||0);
  if (h > 0) return `${h}h ${m}m`;
  return `${m} min`;
}

// Filter out YouTube Shorts (under 120 seconds)
const filtered = episodes.filter(ep => {
  const match = (ep.duration || '').match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!match) return true;
  const totalSeconds = (parseInt(match[1]||0) * 3600) + (parseInt(match[2]||0) * 60) + parseInt(match[3]||0);
  return totalSeconds >= 120;
});

// Return each episode as a separate item
return filtered.slice(0, 5).map(ep => ({
  json: {
    id: ep.id,
    title: ep.title,
    slug: makeSlug(ep.title),
    description: ep.description,
    thumbnail: ep.thumbnailMax || ep.thumbnail,
    publishedAt: ep.publishedAt,
    duration: ep.duration,
    durationFormatted: formatDuration(ep.duration),
    youtubeUrl: `https://www.youtube.com/watch?v=${ep.id}`
  }
}));

const post = $input.first().json.post;
const indexEntry = $input.first().json.indexEntry;
const slug = $input.first().json.slug;

// Base64 encode the blog post JSON for GitHub API
const postJson = JSON.stringify(post, null, 2);
const postBase64 = btoa(unescape(encodeURIComponent(postJson)));

return [{
  json: {
    post,
    indexEntry,
    slug,
    postBase64
  }
}];

const episode = $input.first().json;

const prompt = `You are a blog content writer for The Manage Her® — a women's leadership podcast hosted by Aimee Rickabus, CEO of a nine-figure technology company, bestselling author, and mother of six. Generate an enhanced show notes blog post from this podcast episode.

EPISODE DETAILS:
Title: ${episode.title}
Duration: ${episode.durationFormatted}
Published: ${episode.publishedAt}
YouTube URL: ${episode.youtubeUrl}

EPISODE DESCRIPTION:
${(episode.description || '').substring(0, 8000)}

TRANSCRIPT:
${(episode.transcript || '').substring(0, 50000)}

Generate a JSON response with EXACTLY this structure (no markdown, no backticks, just raw JSON):
{
  "title": "A compelling blog title (different from the episode title, more SEO-friendly, under 80 characters)",
  "episodeNumber": extract the episode number from the title or use 0,
  "guestName": "Guest full name or empty string if solo episode",
  "guestBio": "2-3 sentence bio of the guest based on what is discussed in the episode",
  "excerpt": "A compelling 2-3 sentence summary that makes someone want to listen",
  "metaDescription": "SEO meta description under 160 characters",
  "topics": ["3-5 topic tags from: Leadership, Motherhood, Financial Literacy, Wellness, Entrepreneurship, Boundaries, Identity, Marriage, Community, Spirituality"],
  "keyTakeaways": ["5-7 key takeaways as complete sentences"],
  "guestLinks": Extract any social media or website links for the guest from the episode description. Look for Instagram, LinkedIn, TikTok, YouTube, website URLs, etc. Return as an array of {"label": "Platform Name", "url": "https://..."} objects. If no links found, return empty array.,
  "pullQuotes": [{"text": "A memorable quote from the episode", "timestamp": "MM:SS or empty"}],
  "timestamps": [{"time": "0:00", "label": "Introduction"}, {"time": "5:30", "label": "Topic discussed"}],
  "content": "Full blog post as HTML. Use p tags for paragraphs, strong for emphasis, em for italic, h3 for subheadings. Write 800-1200 words covering the main themes insights and actionable advice. Write in The Manage Her brand voice: bold warm direct permission-giving. Address the reader as you. Do NOT use bullet point lists in the content. Write in flowing prose paragraphs.",
  "quiz": {
    "title": "A compelling self-discovery quiz title related to the episode theme (e.g. What is Your Leadership Superpower?)",
    "description": "1-2 sentence invitation to take the quiz",
    "types": {
      "A": {"name": "2-4 word empowering archetype name", "description": "3-4 sentence personalized result that validates the reader and connects to episode themes. Write in second person. End with why they should listen to this episode."},
      "B": {"name": "archetype name", "description": "..."},
      "C": {"name": "archetype name", "description": "..."},
      "D": {"name": "archetype name", "description": "..."}
    },
    "questions": [
      {
        "question": "A relatable scenario or self-reflection question in second person",
        "options": [
          {"text": "Realistic behavior or belief - not obviously right or wrong", "type": "A"},
          {"text": "Option text", "type": "B"},
          {"text": "Option text", "type": "C"},
          {"text": "Option text", "type": "D"}
        ]
      }
    ]
  }
}

QUIZ RULES: Generate exactly 6 questions with 4 options each (types A/B/C/D). This is a SELF-DISCOVERY quiz not a knowledge test. Questions should help listeners learn about themselves. All options should feel valid. Archetype names should be empowering. Results should make every type feel seen and valued. Tie results back to why this episode would help them.

IMPORTANT: Return ONLY valid JSON. No markdown. No backticks. No preamble. No explanation before or after the JSON.`;

const requestBody = {
  model: "claude-sonnet-4-20250514",
  max_tokens: 6000,
  messages: [
    {
      role: "user",
      content: prompt
    }
  ]
};

return [{
  json: {
    ...episode,
    claudeRequestBody: JSON.stringify(requestBody)
  }
}];

